#include <stdio.h>
#include <math.h>

int gcd(int a, int b) {
    if (b == 0)
        return a;
    return gcd(b, a % b);
}

int lcm(int a, int b) {
    return (a * b) / gcd(a, b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int arr[N];
        for (int i = 0; i < N; i++)
            scanf("%d", &arr[i]);
        int max_len = -1;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                int prod = 1;
                int lcm_val = arr[i];
                for (int k = i; k <= j; k++) {
                    prod *= arr[k];
                    lcm_val = lcm(lcm_val, arr[k]);
                }
                if (lcm_val == prod)
                    max_len = (max_len > (j - i + 1)) ? max_len : (j - i + 1);
            }
        }
        printf("%d\n", max_len);
    }
    return 0;
}

