import java.util.Scanner;
public class Main {
    public static int gcd(int a, int b) {
        if (b == 0)
            return a;
        return gcd(b, a % b);
    }

    public static int lcm(int a, int b) {
        return (a * b) / gcd(a, b);
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] arr = new int[N];
            for (int i = 0; i < N; i++)
                arr[i] = sc.nextInt();
            int max_len = -1;
            for (int i = 0; i < N; i++) {
                for (int j = i + 1; j < N; j++) {
                    int prod = 1;
                    int lcm_val = arr[i];
                    for (int k = i; k <= j; k++) {
                        prod *= arr[k];
                        lcm_val = lcm(lcm_val, arr[k]);
                    }
                    if (lcm_val == prod)
                        max_len = Math.max(max_len, j - i + 1);
                }
            }
            System.out.println(max_len);
        }
    }
}

