        for i in range(N):
            for j in range(i + 1, N):
                prod = 1
                lcm_val = arr[i]
                for k in range(i, j + 1):
                    prod *= arr[k]
                    lcm_val = lcm(lcm_val, arr[k])
                if lcm_val == prod:
                    max_len = max(max_len, j - i + 1)
